mapper.select:
SELECT A.CMPYCD, A.INSP_GB, A.INSP_ORD, A.INSPCD, B.CDNM AS INSP_NM, A.BIGO FROM PD_INSP_CLSFY A LEFT OUTER JOIN HPBA900T_TBL B ON A.CMPYCD = B.CMPYCD AND A.INSPCD = B.CODE AND B.CDGBN = '830' WHERE A.CMPYCD = #{cmpycd}
and a.insp_gb = #{insp_gb}
order by cast(a.insp_ord as INT)

mapper.update:
update pd_insp_clsfy
set insp_ord = #{insp_ord},
    bigo = #{bigo},
    updemp = #{updemp},
    updtime = GETDATE()
where cmpycd = #{cmpycd}
  and insp_gb = #{insp_gb}
  and inspcd = #{inspcd}

mapper.delete:
delete from pd_insp_clsfy
where cmpycd = #{cmpycd}
  and insp_gb = #{insp_gb}
  and inspcd = #{inspcd}
